import AppKit

// The ControlBoard tomoe mark (client/public/favicon.svg rendered at 36px),
// embedded so the status item needs no resource bundle. Drawn at 18pt — the
// 36px bitmap is the @2x rep, so it stays crisp on Retina.
enum Logo {
    private static let png36 = ""

    static func statusImage() -> NSImage? {
        guard let data = Data(base64Encoded: png36), let img = NSImage(data: data) else { return nil }
        img.size = NSSize(width: 18, height: 18)
        img.isTemplate = false // full-colour brand mark, not a monochrome template
        return img
    }
}
